### C++ Program: Dictionary Using Binary Search Tree (BST)

Below is a well-structured C++ program that implements a dictionary using a Binary Search Tree (BST). The program allows users to insert words and their definitions, search for words, delete words, and print the entire dictionary.

```cpp
#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

using namespace std;

// Define the Node structure
struct Node {
    string word;
    string definition;
    Node* left;
    Node* right;

    Node(string w, string d) : word(w), definition(d), left(nullptr), right(nullptr) {}
};

// BST class
class BinarySearchTree {
private:
    Node* root;

    // Helper function to insert a node
    void insert(Node* &node, string word, string definition);

    // Helper function to search for a word
    Node* search(Node* node, string word);

    // Helper function to delete a node
    void deleteNode(Node* &node, string word);

    // Helper function to print the tree
    void printTree(Node* node, int level);

    // Helper function to get all words in the tree
    vector<string> getWords(Node* node);
};

// Insert a word into the BST
void BinarySearchTree::insert(Node* &node, string word, string definition) {
    if (node == nullptr) {
        node = new Node(word, definition);
        return;
    }

    if (word < node->word) {
        insert(node->left, word, definition);
    } else {
        insert(node->right, word, definition);
    }
}

// Search for a word in the BST
Node* BinarySearchTree::search(Node* node, string word) {
    if (node == nullptr) return nullptr;

    if (word == node->word) return node;

    if (word < node->word) return search(node->left, word);
    else return search(node->right, word);
}

// Delete a word from the BST
void BinarySearchTree::deleteNode(Node* &node, string word) {
    if (node == nullptr) return;

    if (word < node->word) {
        deleteNode(node->left, word);
    } else if (word > node->word) {
        deleteNode(node->right, word);
    } else {
        // Node found, delete it
        if (node->left == nullptr) {
            Node* temp = node->right;
            delete node;
            node = temp;
        } else if (node->right == nullptr) {
            Node* temp = node->left;
            delete node;
            node = temp;
        } else {
            // Node has two children, find the in-order successor
            Node* temp = node->right;
            while (temp->left != nullptr) {
                temp = temp->left;
            }

            // Copy the value from the in-order successor
            node->word = temp->word;
            node->definition = temp->definition;

            // Delete the in-order successor
            deleteNode(node->right, temp->word);
        }
    }
}

// Print the tree in-order
void BinarySearchTree::printTree(Node* node, int level) {
    if (node != nullptr) {
        printTree(node->right, level + 1);
        cout << "Level " << level << ": ";
        cout << node->word << " - " << node->definition << endl;
        printTree(node->left, level);
    }
}

// Get all words in the BST
vector<string> BinarySearchTree::getWords(Node* node) {
    vector<string> words;
    if (node != nullptr) {
        words = getWords(node->left);
        words.push_back(node->word);
        words = vector_concat(words, getWords(node->right));
    }
    return words;
}

// Helper function to concatenate two vectors
vector<string> vector_concat(const vector<string>& a, const vector<string>& b) {
    vector<string> result;
    for (const auto& item : a) {
        result.push_back(item);
    }
    for (const auto& item : b) {
        result.push_back(item);
    }
    return result;
}

// Main function
int main() {
    BinarySearchTree bst;

    string inputWord, inputDefinition;
    cout << "Welcome to the Dictionary with BST!\n";
    cout << "Enter words and their definitions (type 'exit' to quit): \n";

    while (true) {
        cout << "Word: ";
        getline(cin, inputWord);
        if (inputWord == "exit") break;

        cout << "Definition: ";
        getline(cin, inputDefinition);

        bst.insert(bst.root, inputWord, inputDefinition);
    }

    cout << "\nDictionary Contents:\n";
    vector<string> words = bst.getWords(bst.root);
    for (const auto& word : words) {
        cout << word << " - " << endl;
    }

    cout << "\nSearch for a word: ";
    getline(cin, inputWord);
    Node* result = bst.search(bst.root, inputWord);
    if (result) {
        cout << "Definition of " << inputWord << ": " << result->definition << endl;
    } else {
        cout << "Word not found in the dictionary.\n";
    }

    cout << "\nDelete a word: ";
    getline(cin, inputWord);
    bst.deleteNode(bst.root, inputWord);

    cout << "\nDictionary after deletion:\n";
    vector<string> updatedWords = bst.getWords(bst.root);
    for (const auto& word : updatedWords) {
        cout << word << " - " << endl;
    }

    return 0;
}
```

---

### Features Implemented:

1. **Insertion**: Users can add words and their definitions into the BST.
2. **Search**: Users can search for a word and retrieve its definition.
3. **Deletion**: Users can delete a specific word and its definition.
4. **Printing**: The dictionary is printed in-order to show the tree structure and words in order.
5. **User Interaction**: The program allows interactive input with clear prompts.

---

### Notes:
- The program uses an in-order traversal for printing the dictionary.
- The `vector_concat` function is used to combine the results of left and right subtrees.
- The program handles deletion properly, especially when a node has two children.

This implementation ensures efficient dictionary operations (insert, search, delete) and provides a clear user interface.

