// BinarySearchTree.swift
import Foundation

// Define a Node structure for the BST
struct Node {
    let value: Int
    let left: Node?
    let right: Node?

    init(_ value: Int) {
        self.value = value
        self.left = nil
        self.right = nil
    }
}

// Define the BST class
class BinarySearchTree {
    var root: Node?

    // Insert a new node into the BST
    func insert(_ value: Int) {
        root = insertNode(root, value)
    }

    private func insertNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return Node(value)
        }

        if value < node!.value {
            node!.left = insertNode(node!.left, value)
        } else {
            node!.right = insertNode(node!.right, value)
        }

        return node!
    }

    // Delete a node from the BST
    func delete(_ value: Int) {
        root = deleteNode(root, value)
    }

    private func deleteNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return nil
        }

        if value < node!.value {
            node!.left = deleteNode(node!.left, value)
        } else if value > node!.value {
            node!.right = deleteNode(node!.right, value)
        } else {
            // Node found, perform deletion
            if node!.left == nil {
                return node!.right
            } else if node!.right == nil {
                return node!.left
            } else {
                // Node has two children, find the in-order successor
                let successor = findInOrderSuccessor(node!.right!)
                let tempValue = successor.value
                node!.value = tempValue

                node!.right = deleteNode(node!.right, tempValue)
            }
        }

        return node!
    }

    // Find the in-order successor of a node
    private func findInOrderSuccessor(_ node: Node?) -> Node? {
        var successor = node
        if successor == nil {
            return nil
        }

        // Traverse to the right to find the smallest node
        while successor?.left != nil {
            successor = successor!.left
        }

        return successor
    }

    // Traverse the tree in Pre-order
    func preOrderTraverse() {
        preOrderTraverse(root)
    }

    private func preOrderTraverse(_ node: Node?) {
        guard let node = node else { return }
        print(node.value, terminator: " ")
        preOrderTraverse(node.left)
        preOrderTraverse(node.right)
    }

    // Traverse the tree in In-order
    func inOrderTraverse() {
        inOrderTraverse(root)
    }

    private func inOrderTraverse(_ node: Node?) {
        guard let node = node else { return }
        inOrderTraverse(node.left)
        print(node.value, terminator: " ")
        inOrderTraverse(node.right)
    }

    // Traverse the tree in Post-order
    func postOrderTraverse() {
        postOrderTraverse(root)
    }

    private func postOrderTraverse(_ node: Node?) {
        guard let node = node else { return }
        postOrderTraverse(node.left)
        postOrderTraverse(node.right)
        print(node.value, terminator: " ")
    }
}
```

### Explanation:
- **Node Structure**: Represents each node in the BST with a value, and pointers to left and right children.
- **Insert**: Adds a new node to the correct position in the BST, maintaining the binary search property.
- **Delete**: Removes a node while preserving BST properties. It handles nodes with one or two children.
- **Traversal**:
  - **Pre-order**: Visits the root first, then the left subtree, then the right.
  - **In-order**: Visits the left subtree, then the root, then the right.
  - **Post-order**: Visits the left, then the right, then the root.

### Usage:
```swift
let bst = BinarySearchTree()
bst.insert(10)
bst.insert(5)
bst.insert(15)
bst.insert(3)
bst.insert(7)
bst.insert(13)

print("Pre-order traversal:")
bst.preOrderTraverse()

print("\nIn-order traversal:")
bst.inOrderTraverse()

print("\nPost-order traversal:")
bst.postOrderTraverse()

bst.delete(10)
print("\nAfter deleting 10:")
bst.preOrderTraverse()
```

This implementation ensures efficient operations with **O(log n)** average time complexity for insert and delete, and **O(n)** in the worst case (e.g., for a skewed tree). The traversal functions are straightforward and maintain the BST properties.

